import{_ as s,H as e,f as i,i as o}from"./chunks/framework.DbTCwA-u.js";const u=JSON.parse('{"title":"Mascotas Holográficas","description":"Cómo configurar los nametags de mascotas en pets.yml.","frontmatter":{"title":"Mascotas Holográficas","description":"Cómo configurar los nametags de mascotas en pets.yml."},"headers":[],"relativePath":"es/config/pets.md","filePath":"es/config/pets.md"}'),t={name:"es/config/pets.md"};function n(l,a,r,d,c,p){return e(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="mascotas-holograficas-pets-yml" tabindex="-1">Mascotas Holográficas (pets.yml) <a class="header-anchor" href="#mascotas-holograficas-pets-yml" aria-label="Permalink to &quot;Mascotas Holográficas (pets.yml)&quot;">​</a></h1><p>El sistema de mascotas es una de las características más innovadoras de EligiusNametag. Con él, cualquier lobo, loro, o gato domado por un jugador recibirá un nametag holográfico flotante que sigue a la mascota fluidamente.</p><h3 id="configuracion-base" tabindex="-1">Configuración Base <a class="header-anchor" href="#configuracion-base" aria-label="Permalink to &quot;Configuración Base&quot;">​</a></h3><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">pets</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  show_unnamed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><ul><li>Si <code>show_unnamed</code> está en <code>true</code>, incluso un lobo genérico domado tendrá un holograma de texto.</li><li>Si lo pones en <code>false</code>, solo las mascotas que el jugador renombre usando un <strong>Yunque</strong> (Name Tag vanilla) activarán el sistema holográfico para conservar un estilo más Vanilla en el servidor general.</li></ul><h3 id="diseno-de-las-lineas" tabindex="-1">Diseño de las Líneas <a class="header-anchor" href="#diseno-de-las-lineas" aria-label="Permalink to &quot;Diseño de las Líneas&quot;">​</a></h3><p>Usa <code>&lt;DISPLAYNAME&gt;</code> para mostrar el nombre que le puso el jugador en el yunque y <code>&lt;PLAYER&gt;</code> para citar al dueño.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  default_format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;gray&gt;Mascota de &lt;PLAYER&gt;&lt;/gray&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;white&gt;&lt;DISPLAYNAME&gt;&lt;/white&gt;&quot;</span></span></code></pre></div><h3 id="🐾-¡el-secreto-mas-importante" tabindex="-1">🐾 ¡El secreto más importante! <a class="header-anchor" href="#🐾-¡el-secreto-mas-importante" aria-label="Permalink to &quot;🐾 ¡El secreto más importante!&quot;">​</a></h3><p>Las mascotas <strong>heredan</strong> el diseño del rango Vault de su dueño. Esto quiere decir que si el dueño de un gato tiene rango &quot;Admin&quot; en <code>players.yml</code>, y el rango Admin tiene un texto rojo y un ícono de fuego, <strong>el gato también lucirá el texto rojo y el ícono de fuego</strong> en su variable de grupo (si lo configuras así cruzando variables PAPI o permisos de LuckPerms a nivel del nodo <code>&lt;PLAYER&gt;</code>).</p>`,10)])])}const g=s(t,[["render",n]]);export{u as __pageData,g as default};
